  6→
  7→export interface SerializeOptions {
  8→  /** Include component definitions that have no instances on canvas (default: true) */
  9→  includeUnusedDefinitions?: boolean;
 10→}
 11→
 12→export function serialize(
 13→  nodes: FlowNode[],
 14→  edges: FlowEdge[],
 15→  direction: FlowDirection,
 16→  componentDefinitions?: ComponentDefinition[],
 17→  options?: SerializeOptions
 18→): string {
 19→  const { includeUnusedDefinitions = true } = options ?? {};
 20→
 21→  // Filter to only definitions that have instances on the canvas
 22→  const usedDefinitions = componentDefinitions && !includeUnusedDefinitions
 23→    ? filterUsedDefinitions(nodes, componentDefinitions)
 24→    : componentDefinitions;
 25→
 26→  const mermaidSection = generateMermaid(nodes, edges, direction, usedDefinitions);
 27→
 28→  const nodesLayout: Record<string, FlowmaidNodeLayout> = {};
 29→  for (const node of nodes) {
 30→    // Skip component child nodes (they're regenerated from definition)
 31→    if (node.data.componentParentId) continue;
 32→    const styleW = (node.style as Record<string, unknown>)?.width as number | undefined;
 33→    const styleH = (node.style as Record<string, unknown>)?.height as number | undefined;
 34→    const w = node.width ?? styleW;
 35→    const h = node.height ?? styleH;
 36→
 37→    const entry: FlowmaidNodeLayout = {
 38→      position: { x: node.position.x, y: node.position.y },
 39→      size: w && h ? { width: w, height: h } : undefined,
 40→      shape: node.data.shape,
 41→      label: node.data.label,
 42→    };
 43→    if (node.data.fillColor) entry.fillColor = node.data.fillColor;
 44→    if (node.data.fillOpacity !== undefined && node.data.fillOpacity !== 10) entry.fillOpacity = node.data.fillOpacity;
 45→    if (node.data.fillLightness !== undefined && node.data.fillLightness !== 5) entry.fillLightness = node.data.fillLightness;
 46→    if (node.data.borderColor) entry.borderColor = node.data.borderColor;
 47→    if (node.data.borderOpacity !== undefined && node.data.borderOpacity !== 10) entry.borderOpacity = node.data.borderOpacity;
 48→    if (node.data.borderLightness !== undefined && node.data.borderLightness !== 5) entry.borderLightness = node.data.borderLightness;
 49→    if (node.data.borderWidth) entry.borderWidth = node.data.borderWidth;
 50→    if (node.data.borderStyle) entry.borderStyle = node.data.borderStyle;
 51→    if (node.zIndex !== undefined && node.zIndex !== 0) entry.zIndex = node.zIndex;
 52→    if (node.data.fontSize) entry.fontSize = node.data.fontSize;
 53→    if (node.data.textColor) entry.textColor = node.data.textColor;
 54→    if (node.data.textOpacity !== undefined && node.data.textOpacity !== 10) entry.textOpacity = node.data.textOpacity;
 55→    if (node.data.textLightness !== undefined && node.data.textLightness !== 5) entry.textLightness = node.data.textLightness;
 56→    if (node.data.textAlign && node.data.textAlign !== "center") entry.textAlign = node.data.textAlign;
 57→    if (node.data.bold) entry.bold = node.data.bold;
 58→    if (node.data.italic) entry.italic = node.data.italic;
 59→    if (node.data.underline) entry.underline = node.data.underline;
 60→    if (node.data.componentDefinitionId) entry.componentDefinitionId = node.data.componentDefinitionId as string;
 61→    if (node.data.componentInstanceName) entry.componentInstanceName = node.data.componentInstanceName as string;
 62→    if (node.data.componentSyncVersion !== undefined) entry.componentSyncVersion = node.data.componentSyncVersion as number;
 63→    if (node.data.collapsed) entry.collapsed = true;
 64→    if (node.data.expandedSize) entry.expandedSize = node.data.expandedSize as { width: number; height: number };
 65→
 66→    nodesLayout[node.id] = entry;
 67→  }
 68→
 69→  // Build set of component child node IDs to filter internal edges
 70→  const componentChildIds = new Set(nodes.filter((n) => n.data.componentParentId).map((n) => n.id));
 71→
 72→  const edgesLayout: Record<string, FlowmaidEdgeLayout> = {};
 73→  for (const edge of edges) {
 74→    // Skip bridge edges
 75→    if (edge.data?.isBridgeEdge) continue;
 76→    // Skip internal edges between component children
 77→    if (componentChildIds.has(edge.source) && componentChildIds.has(edge.target)) continue;
 78→    const entry: FlowmaidEdgeLayout = {
 79→      source: edge.source,
 80→      target: edge.target,
 81→    };
 82→    if (edge.data?.label) entry.label = edge.data.label;
 83→    if (edge.sourceHandle) entry.sourceHandle = edge.sourceHandle;
 84→    if (edge.targetHandle) entry.targetHandle = edge.targetHandle;
 85→    if (edge.data?.edgeType && edge.data.edgeType !== "bezier") entry.edgeType = edge.data.edgeType;
 86→    if (edge.data?.markerStart) entry.markerStart = edge.data.markerStart;
 87→    if (edge.data?.markerEnd && edge.data.markerEnd !== "arrowclosed") entry.markerEnd = edge.data.markerEnd;
 88→    if (edge.data?.strokeWidth && edge.data.strokeWidth !== 2) entry.strokeWidth = edge.data.strokeWidth;
 89→    if (edge.data?.strokeColor) entry.strokeColor = edge.data.strokeColor;
 90→    if (edge.data?.strokeOpacity !== undefined && edge.data.strokeOpacity !== 10) entry.strokeOpacity = edge.data.strokeOpacity;
 91→    if (edge.data?.strokeLightness !== undefined && edge.data.strokeLightness !== 5) entry.strokeLightness = edge.data.strokeLightness;
 92→    if (edge.data?.strokeStyle && edge.data.strokeStyle !== "solid") entry.strokeStyle = edge.data.strokeStyle;
 93→    if (edge.data?.waypoints && edge.data.waypoints.length > 0) entry.waypoints = edge.data.waypoints;
 94→
 95→    edgesLayout[edge.id] = entry;
 96→  }
 97→
 98→  const layout: FlowmaidLayout = {
 99→    direction,
100→    nodes: nodesLayout,
101→    edges: edgesLayout,
102→    ...(usedDefinitions && usedDefinitions.length > 0 && { componentDefinitions: usedDefinitions }),
103→  };
104→
105→  const layoutSection = stringify(layout);
106→
107→  return `--- mermaid ---\n${mermaidSection}\n\n--- layout ---\n${layoutSection}`;
108→}
109→
110→/**
111→ * Serialize only the selected nodes/edges (+ related edges) for filtered preview.
112→ * Returns the same format as serialize() but with only the relevant layout entries.
113→ * Mermaid section is always included in full.
114→ */
115→export function serializeFiltered(
116→  nodes: FlowNode[],
117→  edges: FlowEdge[],
118→  direction: FlowDirection,
119→  componentDefinitions: ComponentDefinition[] | undefined,
120→  selectedNodeIds: string[],
121→  selectedEdgeIds: string[]
122→): string {
123→  const full = serialize(nodes, edges, direction, componentDefinitions);
124→  if (selectedNodeIds.length === 0 && selectedEdgeIds.length === 0) return full;
125→
126→  const parts = full.split("--- layout ---\n");
127→  if (parts.length < 2) return full;
128→
129→  const mermaidPart = parts[0];
130→  const layoutYaml = parts[1];
131→
132→  const layout = parse(layoutYaml) as FlowmaidLayout | null;
133→  if (!layout) return full;
134→
135→  const nodeIdSet = new Set(selectedNodeIds);
136→  const edgeIdSet = new Set(selectedEdgeIds);
137→
138→  const filteredLayout: FlowmaidLayout = {
139→    direction: layout.direction,
140→    nodes: {},
141→    edges: {},
142→  };
143→
144→  if (layout.nodes) {
145→    for (const [id, node] of Object.entries(layout.nodes)) {
146→      if (nodeIdSet.has(id)) filteredLayout.nodes[id] = node;
147→    }
148→  }
149→  if (layout.edges) {
150→    for (const [id, edge] of Object.entries(layout.edges)) {
151→      if (edgeIdSet.has(id)) filteredLayout.edges[id] = edge;
152→    }
153→  }
154→  if (layout.componentDefinitions) {
155→    filteredLayout.componentDefinitions = layout.componentDefinitions;
156→  }
157→
158→  const filteredSection = stringify(filteredLayout);
159→
160→  return `${mermaidPart}--- layout ---\n${filteredSection}`;
161→}
162→
163→/**
164→ * Filter component definitions to only those that have instances on the canvas.
165→ */
166→export function filterUsedDefinitions(
167→  nodes: FlowNode[],
168→  definitions: ComponentDefinition[]
169→): ComponentDefinition[] {
170→  const usedDefIds = new Set(
171→    nodes
172→      .filter((n) => n.type === "componentInstance" && n.data.componentDefinitionId)
173→      .map((n) => n.data.componentDefinitionId as string)
174→  );
175→  return definitions.filter((d) => usedDefIds.has(d.id));
176→}
