  5→import { Minus, Plus } from "lucide-react";
  6→import { ConnectHandle } from "./ConnectHandle";
  7→import { useFlowStore } from "@/store/useFlowStore";
  8→import { computeColor } from "@/lib/color";
  9→import { strokeDasharray } from "./svgBorderUtils";
 10→import type { FlowNode } from "@/store/types";
 11→
 12→export const ComponentInstanceNode = memo(function ComponentInstanceNode({ id, data, selected }: NodeProps<FlowNode>) {
 13→  const collapsed = data.collapsed ?? false;
 14→  const toggleComponentCollapse = useFlowStore((s) => s.toggleComponentCollapse);
 15→  const updateComponentInstanceName = useFlowStore((s) => s.updateComponentInstanceName);
 16→  const direction = useFlowStore((s) => s.direction);
 17→
 18→  const [editingName, setEditingName] = useState(false);
 19→  const [nameValue, setNameValue] = useState(data.componentInstanceName ?? "");
 20→  const nameInputRef = useRef<HTMLInputElement>(null);
 21→  const [hovered, setHovered] = useState(false);
 22→  const handleVisible = hovered || !!selected;
 23→
 24→  // Compute style colors
 25→  const computedFill = computeColor(data.fillColor, data.fillOpacity, data.fillLightness);
 26→  const computedBorder = computeColor(data.borderColor, data.borderOpacity, data.borderLightness);
 27→  const computedText = computeColor(data.textColor, data.textOpacity, data.textLightness);
 28→  const borderWidth = data.borderWidth ?? 2;
 29→  const borderStyle = data.borderStyle ?? "solid";
 30→  const fontSize = data.fontSize ?? 14;
 31→  const textStyle: React.CSSProperties = {
 32→    color: computedText ?? "var(--foreground)",
 33→    fontWeight: data.bold ? "bold" : undefined,
 34→    fontStyle: data.italic ? "italic" : undefined,
 35→    textDecoration: data.underline ? "underline" : undefined,
 36→  };
 37→
 38→  // Direction-aware: TD → top=target, bottom=source; LR → left=target, right=source
 39→  const entryPos = direction === "LR" ? Position.Left : Position.Top;
 40→  const exitPos = direction === "LR" ? Position.Right : Position.Bottom;
 41→
 42→  useEffect(() => {
 43→    setNameValue(data.componentInstanceName ?? "");
 44→  }, [data.componentInstanceName]);
 45→
 46→  useEffect(() => {
 47→    if (editingName && nameInputRef.current) {
 48→      nameInputRef.current.focus();
 49→      nameInputRef.current.select();
 50→    }
 51→  }, [editingName]);
 52→
 53→  const commitName = useCallback(() => {
 54→    setEditingName(false);
 55→    const trimmed = nameValue.trim();
 56→    if (trimmed && trimmed !== (data.componentInstanceName ?? "")) {
 57→      updateComponentInstanceName(id, trimmed);
 58→    } else {
 59→      setNameValue(data.componentInstanceName ?? "");
 60→    }
 61→  }, [nameValue, data.componentInstanceName, id, updateComponentInstanceName]);
 62→
 63→  // Hidden handles for bridge edge internal connections (entry-incoming + exit-outgoing only)
 64→  const bridgeHandles = (
 65→    <>
 66→      <Handle
 67→        type="source"
 68→        position={entryPos}
 69→        id="bridge-entry-source"
 70→        isConnectable={false}
 71→        style={{ width: 0, height: 0, opacity: 0, pointerEvents: "none" }}
 72→      />
 73→      <Handle
 74→        type="target"
 75→        position={exitPos}
 76→        id="bridge-exit-target"
 77→        isConnectable={false}
 78→        style={{ width: 0, height: 0, opacity: 0, pointerEvents: "none" }}
 79→      />
 80→    </>
 81→  );
 82→
 83→  // Collapsed view — predefined process shape (rectangle with vertical lines on sides)
 84→  if (collapsed) {
 85→    return (
 86→      <div
 87→        className="relative w-full h-full"
 88→        onMouseEnter={() => setHovered(true)}
 89→        onMouseLeave={() => setHovered(false)}
 90→      >
 91→        <svg
 92→          className="absolute inset-0 w-full h-full"
 93→          viewBox="0 0 100 100"
 94→          preserveAspectRatio="none"
 95→        >
 96→          <rect
 97→            x="0" y="0" width="100" height="100"
 98→            fill={computedFill ?? "var(--muted)"}
 99→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
100→            strokeWidth={borderWidth}
101→            vectorEffect="non-scaling-stroke"
102→            strokeDasharray={strokeDasharray(borderStyle)}
103→          />
104→          <line
105→            x1="8" y1="0" x2="8" y2="100"
106→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
107→            strokeWidth={borderWidth}
108→            vectorEffect="non-scaling-stroke"
109→            strokeDasharray={strokeDasharray(borderStyle)}
110→          />
111→          <line
112→            x1="92" y1="0" x2="92" y2="100"
113→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
114→            strokeWidth={borderWidth}
115→            vectorEffect="non-scaling-stroke"
116→            strokeDasharray={strokeDasharray(borderStyle)}
117→          />
118→        </svg>
119→        <div className="relative flex items-center w-full h-full px-5" style={textStyle}>
120→          {editingName ? (
121→            <input
122→              ref={nameInputRef}
123→              className="nodrag bg-transparent outline-none border-b border-foreground/30 flex-1 min-w-0 text-center"
124→              style={{ color: "inherit", fontSize }}
125→              value={nameValue}
126→              onChange={(e) => setNameValue(e.target.value)}
127→              onBlur={commitName}
128→              onKeyDown={(e) => {
129→                if (e.key === "Enter") commitName();
130→                if (e.key === "Escape") { setNameValue(data.componentInstanceName ?? ""); setEditingName(false); }
131→              }}
132→            />
133→          ) : (
134→            <span
135→              className="flex-1 font-medium truncate text-center cursor-default"
136→              style={{ fontSize }}
137→              onDoubleClick={(e) => { e.stopPropagation(); setEditingName(true); }}
138→            >
139→              {data.componentInstanceName ?? data.label}
140→            </span>
141→          )}
142→          <button
143→            className="nodrag shrink-0 flex items-center justify-center w-5 h-5 rounded border cursor-pointer"
144→            style={{ background: "var(--background)", borderColor: "color-mix(in srgb, var(--foreground) 50%, transparent)" }}
145→            onClick={() => toggleComponentCollapse(id)}
146→            title="Expand"
147→          >
148→            <Plus size={12} />
149→          </button>
150→        </div>
151→        <ConnectHandle pos={entryPos} type="target" visible={handleVisible} nodeId={id} />
152→        <ConnectHandle pos={entryPos} type="source" visible={handleVisible} nodeId={id} />
153→        <ConnectHandle pos={exitPos} type="target" visible={handleVisible} nodeId={id} />
154→        <ConnectHandle pos={exitPos} type="source" visible={handleVisible} nodeId={id} />
155→        {bridgeHandles}
156→      </div>
157→    );
158→  }
159→
160→  // Expanded view - just a container with header; child nodes are rendered by React Flow
161→  return (
162→    <div
163→      className="w-full h-full"
164→      onMouseEnter={() => setHovered(true)}
165→      onMouseLeave={() => setHovered(false)}
166→    >
167→      <NodeResizer
168→        isVisible={!!selected}
169→        minWidth={180}
170→        minHeight={80}
171→        lineClassName="!border-primary"
172→        handleClassName="!w-2 !h-2 !bg-primary !border-primary"
173→      />
174→      <ConnectHandle pos={entryPos} type="target" visible={handleVisible} nodeId={id} />
175→      <ConnectHandle pos={entryPos} type="source" visible={handleVisible} nodeId={id} />
176→      <ConnectHandle pos={exitPos} type="target" visible={handleVisible} nodeId={id} />
177→      <ConnectHandle pos={exitPos} type="source" visible={handleVisible} nodeId={id} />
178→      {bridgeHandles}
179→      <div
180→        className="w-full h-full rounded-md overflow-hidden flex flex-col"
181→        style={{
182→          border: `${borderWidth}px ${borderStyle} ${computedBorder ?? "var(--color-muted-foreground)"}`,
183→        }}
184→      >
185→        {/* Header */}
186→        <div
187→          className="flex items-center gap-2 px-3 py-1.5 shrink-0"
188→          style={{ background: computedFill ?? "var(--muted)", ...textStyle }}
189→        >
190→          {editingName ? (
191→            <input
192→              ref={nameInputRef}
193→              className="nodrag bg-transparent outline-none border-b border-foreground/30 flex-1 min-w-0"
194→              style={{ color: "inherit", fontSize }}
195→              value={nameValue}
196→              onChange={(e) => setNameValue(e.target.value)}
197→              onBlur={commitName}
198→              onKeyDown={(e) => {
199→                if (e.key === "Enter") commitName();
200→                if (e.key === "Escape") { setNameValue(data.componentInstanceName ?? ""); setEditingName(false); }
201→              }}
202→            />
203→          ) : (
204→            <span
205→              className="font-semibold truncate flex-1 cursor-default"
206→              style={{ fontSize }}
207→              onDoubleClick={(e) => { e.stopPropagation(); setEditingName(true); }}
208→            >
209→              {data.componentInstanceName ?? data.label}
210→            </span>
