 37→export function generateComponentChildren(opts: GenerateChildrenOptions): GenerateChildrenResult {
 38→  const { parentId, def, hidden = false } = opts;
 39→
 40→  // Exclude entry/exit nodes
 41→  const excludeIds = new Set<string>();
 42→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
 43→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
 44→
 45→  // Find min position to normalize origin
 46→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
 47→  const minX = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.x)) : 0;
 48→  const minY = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.y)) : 0;
 49→
 50→  const childNodes: FlowNode[] = visibleNodes
 51→    .map((n) => {
 52→      const origW = n.style?.width ?? CHILD_NODE_W;
 53→      const origH = n.style?.height ?? CHILD_NODE_H;
 54→      return {
 55→        id: `${parentId}_${n.id}`,
 56→        type: n.shape,
 57→        position: {
 58→          x: (n.position.x - minX) * CHILD_SCALE + COMPONENT_PADDING,
 59→          y: (n.position.y - minY) * CHILD_SCALE + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING,
 60→        },
 61→        parentId,
 62→        extent: "parent" as const,
 63→        selectable: false,
 64→        draggable: false,
 65→        data: {
 66→          label: n.label,
 67→          shape: n.shape as NodeShape,
 68→          componentParentId: parentId,
 69→          componentInternalId: n.id,
 70→          ...(n.fillColor ? { fillColor: n.fillColor } : {}),
 71→          ...(n.fillOpacity !== undefined ? { fillOpacity: n.fillOpacity } : {}),
 72→          ...(n.fillLightness !== undefined ? { fillLightness: n.fillLightness } : {}),
 73→          ...(n.borderColor ? { borderColor: n.borderColor } : {}),
 74→          ...(n.borderOpacity !== undefined ? { borderOpacity: n.borderOpacity } : {}),
 75→          ...(n.borderLightness !== undefined ? { borderLightness: n.borderLightness } : {}),
 76→          ...(n.borderWidth ? { borderWidth: n.borderWidth } : {}),
 77→          ...(n.borderStyle ? { borderStyle: n.borderStyle } : {}),
 78→          ...(n.fontSize ? { fontSize: n.fontSize } : {}),
 79→          ...(n.textColor ? { textColor: n.textColor } : {}),
 80→          ...(n.textOpacity !== undefined ? { textOpacity: n.textOpacity } : {}),
 81→          ...(n.textLightness !== undefined ? { textLightness: n.textLightness } : {}),
 82→          ...(n.textAlign ? { textAlign: n.textAlign } : {}),
 83→          ...(n.bold ? { bold: n.bold } : {}),
 84→          ...(n.italic ? { italic: n.italic } : {}),
 85→          ...(n.underline ? { underline: n.underline } : {}),
 86→        },
 87→        style: {
 88→          width: Math.round(origW * CHILD_SCALE),
 89→          height: Math.round(origH * CHILD_SCALE),
 90→        },
 91→        hidden,
 92→      };
 93→    });
 94→
 95→  // Exclude edges connected to entry/exit nodes
 96→  // Default handles for child edges: TD layout (top-down flow inside component)
 97→  const defaultSourceHandle = "bottom-source";
 98→  const defaultTargetHandle = "top-target";
 99→
100→  const childEdges: FlowEdge[] = def.edges
101→    .filter((e) => !excludeIds.has(e.source) && !excludeIds.has(e.target))
102→    .map((e) => ({
103→      id: `${parentId}_${e.id}`,
104→      source: `${parentId}_${e.source}`,
105→      target: `${parentId}_${e.target}`,
106→      sourceHandle: e.sourceHandle ?? defaultSourceHandle,
107→      targetHandle: e.targetHandle ?? defaultTargetHandle,
108→      type: "labeled",
109→      selectable: false,
110→      markerEnd: markerStyleToMarker(e.markerEnd ?? "arrowclosed", e.strokeColor) ?? { type: MarkerType.ArrowClosed },
111→      markerStart: markerStyleToMarker(e.markerStart, e.strokeColor),
112→      data: {
113→        label: e.label ?? "",
114→        edgeType: (e.edgeType ?? "bezier") as EdgeType,
115→        markerStart: e.markerStart,
116→        markerEnd: e.markerEnd ?? ("arrowclosed" as const),
117→        ...(e.strokeWidth ? { strokeWidth: e.strokeWidth } : {}),
118→        ...(e.strokeColor ? { strokeColor: e.strokeColor } : {}),
119→        ...(e.strokeOpacity !== undefined ? { strokeOpacity: e.strokeOpacity } : {}),
120→        ...(e.strokeLightness !== undefined ? { strokeLightness: e.strokeLightness } : {}),
121→        ...(e.strokeStyle ? { strokeStyle: e.strokeStyle } : {}),
122→      },
123→      hidden,
124→    }));
125→
126→  return { childNodes, childEdges };
127→}
