214→export function getEntryExitConnections(def: ComponentDefinition): {
215→  entryTargets: { nodeId: string; edgeProps: ComponentInternalEdge }[];
216→  exitSources: { nodeId: string; edgeProps: ComponentInternalEdge }[];
217→} {
218→  const entryTargets: { nodeId: string; edgeProps: ComponentInternalEdge }[] = [];
219→  const exitSources: { nodeId: string; edgeProps: ComponentInternalEdge }[] = [];
220→
221→  for (const e of def.edges) {
222→    if (def.entryNodeId && e.source === def.entryNodeId) {
223→      entryTargets.push({ nodeId: e.target, edgeProps: e });
224→    }
225→    if (def.exitNodeId && e.target === def.exitNodeId) {
226→      exitSources.push({ nodeId: e.source, edgeProps: e });
227→    }
228→  }
229→
230→  return { entryTargets, exitSources };
231→}
