233→function makeBridgeEdge(
234→  id: string,
235→  source: string,
236→  sourceHandle: string,
237→  target: string,
238→  targetHandle: string | undefined,
239→): FlowEdge {
240→  return {
241→    id,
242→    source,
243→    sourceHandle,
244→    target,
245→    targetHandle,
246→    type: "labeled",
247→    selectable: false,
248→    markerEnd: { type: MarkerType.ArrowClosed },
249→    data: {
250→      label: "",
251→      edgeType: "straight",
252→      markerEnd: "arrowclosed",
253→      isBridgeEdge: true,
254→    },
255→  };
256→}
