258→export function generateBridgeEdges(opts: {
259→  parentId: string;
260→  def: ComponentDefinition;
261→  allEdges: FlowEdge[];
262→  direction?: "TD" | "LR";
263→}): FlowEdge[] {
264→  const { parentId, def, allEdges, direction = "TD" } = opts;
265→  const { entryTargets, exitSources } = getEntryExitConnections(def);
266→  const bridgeEdges: FlowEdge[] = [];
267→
268→  // Direction-aware position names for entry/exit
269→  const entryPosition = direction === "LR" ? "left" : "top";
270→  const exitPosition = direction === "LR" ? "right" : "bottom";
271→
272→  function getHandlePosition(handleId: string | null | undefined): string | null {
273→    if (!handleId) return null;
274→    return handleId.split("-")[0];
275→  }
276→
277→  // 2 bridge patterns (natural flow direction only):
278→  // 1. Entry incoming: External → parent entry → bridge → entryTarget children
279→  // 2. Exit outgoing: exitSource children → bridge → parent exit → External
280→
281→  for (const extEdge of allEdges) {
282→    if (extEdge.data?.isBridgeEdge) continue;
283→
284→    const connectsAsTarget = extEdge.target === parentId;
285→    const connectsAsSource = extEdge.source === parentId;
286→    if (!connectsAsTarget && !connectsAsSource) continue;
287→
288→    const targetPos = connectsAsTarget ? getHandlePosition(extEdge.targetHandle) : null;
289→    const sourcePos = connectsAsSource ? getHandlePosition(extEdge.sourceHandle) : null;
290→
291→    // Determine which position on the parent this edge connects to
292→    // Require explicit handle position — skip edges with unknown handles
293→    const atEntry =
294→      (connectsAsTarget && targetPos === entryPosition) ||
295→      (connectsAsSource && sourcePos === entryPosition);
296→    const atExit =
297→      (connectsAsSource && sourcePos === exitPosition) ||
298→      (connectsAsTarget && targetPos === exitPosition);
299→
300→    // Bridge only for natural flow directions:
301→    // Entry incoming: External → parent entry → bridge → entryTarget children
302→    // Exit outgoing: exitSource children → bridge → parent exit → External
303→    if (atEntry && connectsAsTarget) {
304→      for (const { nodeId } of entryTargets) {
305→        const childId = `${parentId}_${nodeId}`;
306→        bridgeEdges.push(makeBridgeEdge(
307→          `bridge_${parentId}_${extEdge.id}_entry_${nodeId}`,
308→          parentId, "bridge-entry-source", childId, undefined,
309→        ));
310→      }
311→    }
312→
313→    if (atExit && connectsAsSource) {
314→      for (const { nodeId } of exitSources) {
315→        const childId = `${parentId}_${nodeId}`;
316→        bridgeEdges.push(makeBridgeEdge(
317→          `bridge_${parentId}_${extEdge.id}_exit_${nodeId}`,
318→          childId, `${exitPosition}-source`, parentId, "bridge-exit-target",
319→        ));
320→      }
321→    }
322→  }
323→
324→  return bridgeEdges;
325→}
