110→/**
111→ * Serialize only the selected nodes/edges (+ related edges) for filtered preview.
112→ * Returns the same format as serialize() but with only the relevant layout entries.
113→ * Mermaid section is always included in full.
114→ */
115→export function serializeFiltered(
116→  nodes: FlowNode[],
117→  edges: FlowEdge[],
118→  direction: FlowDirection,
119→  componentDefinitions: ComponentDefinition[] | undefined,
120→  selectedNodeIds: string[],
121→  selectedEdgeIds: string[]
122→): string {
123→  const full = serialize(nodes, edges, direction, componentDefinitions);
124→  if (selectedNodeIds.length === 0 && selectedEdgeIds.length === 0) return full;
125→
126→  const parts = full.split("--- layout ---\n");
127→  if (parts.length < 2) return full;
128→
129→  const mermaidPart = parts[0];
130→  const layoutYaml = parts[1];
131→
132→  const layout = parse(layoutYaml) as FlowmaidLayout | null;
133→  if (!layout) return full;
134→
135→  const nodeIdSet = new Set(selectedNodeIds);
136→  const edgeIdSet = new Set(selectedEdgeIds);
137→
138→  const filteredLayout: FlowmaidLayout = {
139→    direction: layout.direction,
140→    nodes: {},
141→    edges: {},
142→  };
143→
144→  if (layout.nodes) {
145→    for (const [id, node] of Object.entries(layout.nodes)) {
146→      if (nodeIdSet.has(id)) filteredLayout.nodes[id] = node;
147→    }
148→  }
149→  if (layout.edges) {
150→    for (const [id, edge] of Object.entries(layout.edges)) {
151→      if (edgeIdSet.has(id)) filteredLayout.edges[id] = edge;
152→    }
153→  }
154→  if (layout.componentDefinitions) {
155→    filteredLayout.componentDefinitions = layout.componentDefinitions;
156→  }
157→
158→  const filteredSection = stringify(filteredLayout);
159→
160→  return `${mermaidPart}--- layout ---\n${filteredSection}`;
161→}
