  Display: "display",
  Text: "text",
} as const;

export type NodeShape = (typeof NodeShape)[keyof typeof NodeShape];

export const FlowDirection = {
  TopDown: "TD",
  LeftRight: "LR",
} as const;

export type FlowDirection =
  (typeof FlowDirection)[keyof typeof FlowDirection];

export const EdgeType = {
