      (connectsAsTarget && targetPos === entryPosition) ||
      (connectsAsSource && sourcePos === entryPosition);
    const atExit =
      (connectsAsSource && sourcePos === exitPosition) ||
      (connectsAsTarget && targetPos === exitPosition);

