  const { parentId, def, hidden = false } = opts;

  // Exclude entry/exit nodes
  const excludeIds = new Set<string>();
  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
  if (def.exitNodeId) excludeIds.add(def.exitNodeId);

