 47→  const exitPos = direction === "LR" ? Position.Right : Position.Bottom;
 48→
 49→  useEffect(() => {
 50→    setNameValue(data.componentInstanceName ?? "");
 51→  }, [data.componentInstanceName]);
 52→
 53→  useEffect(() => {
 54→    if (editingName && nameInputRef.current) {
 55→      nameInputRef.current.focus();
