 99→          className="absolute inset-0 w-full h-full"
100→          viewBox="0 0 100 100"
101→          preserveAspectRatio="none"
102→        >
103→          <rect
104→            x="0" y="0" width="100" height="100"
105→            fill={computedFill ?? "var(--muted)"}
106→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
107→            strokeWidth={borderWidth}
108→            vectorEffect="non-scaling-stroke"
109→            strokeDasharray={strokeDasharray(borderStyle)}
110→          />
111→          <line
112→            x1="8" y1="0" x2="8" y2="100"
113→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
114→            strokeWidth={borderWidth}
115→            vectorEffect="non-scaling-stroke"
116→            strokeDasharray={strokeDasharray(borderStyle)}
117→          />
118→          <line
119→            x1="92" y1="0" x2="92" y2="100"
120→            stroke={computedBorder ?? "var(--color-muted-foreground)"}
121→            strokeWidth={borderWidth}
122→            vectorEffect="non-scaling-stroke"
123→            strokeDasharray={strokeDasharray(borderStyle)}
124→          />
125→        </svg>
126→        <div className="relative flex items-center w-full h-full px-5" style={textStyle}>
127→          {editingName ? (
128→            <input
129→              ref={nameInputRef}
130→              className="nodrag bg-transparent outline-none border-b border-foreground/30 flex-1 min-w-0 text-center"
131→              style={{ color: "inherit", fontSize }}
132→              value={nameValue}
133→              onChange={(e) => setNameValue(e.target.value)}
134→              onBlur={commitName}
135→              onKeyDown={(e) => {
136→                if (e.key === "Enter") commitName();
