138→              }}
139→            />
140→          ) : (
141→            <span
142→              className="flex-1 font-medium truncate text-center cursor-default"
143→              style={{ fontSize }}
144→              onDoubleClick={(e) => { e.stopPropagation(); setEditingName(true); }}
145→            >
146→              {data.componentInstanceName ?? data.label}
147→            </span>
148→          )}
149→          <button
150→            className="nodrag shrink-0 flex items-center justify-center w-5 h-5 rounded border cursor-pointer"
151→            style={{ background: "var(--background)", borderColor: "color-mix(in srgb, var(--foreground) 50%, transparent)" }}
152→            onClick={() => toggleComponentCollapse(id)}
153→            title="Expand"
154→          >
155→            <Plus size={12} />
156→          </button>
157→        </div>
158→        <ConnectHandle pos={entryPos} type="target" visible={handleVisible} nodeId={id} />
159→        <ConnectHandle pos={entryPos} type="source" visible={handleVisible} nodeId={id} />
160→        <ConnectHandle pos={exitPos} type="target" visible={handleVisible} nodeId={id} />
161→        <ConnectHandle pos={exitPos} type="source" visible={handleVisible} nodeId={id} />
162→        {bridgeHandles}
163→      </div>
164→    );
165→  }
166→
167→  // Expanded view - just a container with header; child nodes are rendered by React Flow
168→  return (
169→    <div
170→      className="w-full h-full"
171→      onMouseEnter={() => setHovered(true)}
172→      onMouseLeave={() => setHovered(false)}
173→    >
174→      <NodeResizer
175→        isVisible={!!selected}
176→        minWidth={180}
177→        minHeight={80}
178→        lineClassName="!border-primary"
