181→      <ConnectHandle pos={entryPos} type="target" visible={handleVisible} nodeId={id} />
182→      <ConnectHandle pos={entryPos} type="source" visible={handleVisible} nodeId={id} />
183→      <ConnectHandle pos={exitPos} type="target" visible={handleVisible} nodeId={id} />
