185→      {bridgeHandles}
186→      <div
187→        className="w-full h-full rounded-md overflow-hidden flex flex-col"
188→        style={{
189→          border: `${borderWidth}px ${borderStyle} ${computedBorder ?? "var(--color-muted-foreground)"}`,
190→        }}
191→      >
192→        {/* Header */}
193→        <div
194→          className="flex items-center gap-2 px-3 py-1.5 shrink-0"
195→          style={{ background: computedFill ?? "var(--muted)", ...textStyle }}
196→        >
197→          {editingName ? (
198→            <input
199→              ref={nameInputRef}
200→              className="nodrag bg-transparent outline-none border-b border-foreground/30 flex-1 min-w-0"
201→              style={{ color: "inherit", fontSize }}
202→              value={nameValue}
203→              onChange={(e) => setNameValue(e.target.value)}
204→              onBlur={commitName}
205→              onKeyDown={(e) => {
206→                if (e.key === "Enter") commitName();
207→                if (e.key === "Escape") { setNameValue(data.componentInstanceName ?? ""); setEditingName(false); }
208→              }}
209→            />
210→          ) : (
211→            <span
212→              className="font-semibold truncate flex-1 cursor-default"
213→              style={{ fontSize }}
214→              onDoubleClick={(e) => { e.stopPropagation(); setEditingName(true); }}
215→            >
216→              {data.componentInstanceName ?? data.label}
217→            </span>
218→          )}
219→          <button
220→            className="nodrag shrink-0 flex items-center justify-center w-5 h-5 rounded border cursor-pointer"
221→            style={{ background: "var(--background)", borderColor: "color-mix(in srgb, var(--foreground) 50%, transparent)" }}
222→            onClick={() => toggleComponentCollapse(id)}
223→            title="Collapse"
224→          >
225→            <Minus size={12} />
226→          </button>
227→        </div>
228→
229→        {/* Body area - child nodes are rendered by React Flow as real nodes */}
