216→export function getEntryExitConnections(def: ComponentDefinition): {
217→  entryTargets: { nodeId: string; edgeProps: ComponentInternalEdge }[];
218→  exitSources: { nodeId: string; edgeProps: ComponentInternalEdge }[];
219→} {
220→  const entryTargets: { nodeId: string; edgeProps: ComponentInternalEdge }[] = [];
221→  const exitSources: { nodeId: string; edgeProps: ComponentInternalEdge }[] = [];
222→
223→  for (const e of def.edges) {
224→    if (def.entryNodeId && e.source === def.entryNodeId) {
225→      entryTargets.push({ nodeId: e.target, edgeProps: e });
226→    }
227→    if (def.exitNodeId && e.target === def.exitNodeId) {
228→      exitSources.push({ nodeId: e.source, edgeProps: e });
229→    }
230→  }
231→
232→  return { entryTargets, exitSources };
233→}
