235→function makeBridgeEdge(
236→  id: string,
237→  source: string,
238→  sourceHandle: string,
239→  target: string,
240→  targetHandle: string | undefined,
241→): FlowEdge {
242→  return {
243→    id,
244→    source,
245→    sourceHandle,
246→    target,
247→    targetHandle,
248→    type: "labeled",
249→    selectable: false,
250→    markerEnd: { type: MarkerType.ArrowClosed },
251→    data: {
252→      label: "",
253→      edgeType: "straight",
254→      markerEnd: "arrowclosed",
255→      isBridgeEdge: true,
256→    },
257→  };
258→}
259→
260→export function generateBridgeEdges(opts: {
261→  parentId: string;
262→  def: ComponentDefinition;
263→  allEdges: FlowEdge[];
264→  direction?: "TD" | "LR";
265→}): FlowEdge[] {
266→  const { parentId, def, allEdges, direction = "TD" } = opts;
267→  const { entryTargets, exitSources } = getEntryExitConnections(def);
268→  const bridgeEdges: FlowEdge[] = [];
269→
270→  // Direction-aware position names for entry/exit
271→  const entryPosition = direction === "LR" ? "left" : "top";
272→  const exitPosition = direction === "LR" ? "right" : "bottom";
273→
274→  function getHandlePosition(handleId: string | null | undefined): string | null {
275→    if (!handleId) return null;
276→    return handleId.split("-")[0];
277→  }
278→
279→  // 2 bridge patterns (natural flow direction only):
280→  // 1. Entry incoming: External → parent entry → bridge → entryTarget children
281→  // 2. Exit outgoing: exitSource children → bridge → parent exit → External
282→
283→  for (const extEdge of allEdges) {
284→    if (extEdge.data?.isBridgeEdge) continue;
285→
286→    const connectsAsTarget = extEdge.target === parentId;
287→    const connectsAsSource = extEdge.source === parentId;
288→    if (!connectsAsTarget && !connectsAsSource) continue;
289→
290→    const targetPos = connectsAsTarget ? getHandlePosition(extEdge.targetHandle) : null;
291→    const sourcePos = connectsAsSource ? getHandlePosition(extEdge.sourceHandle) : null;
292→
293→    // Determine which position on the parent this edge connects to
294→    // Require explicit handle position — skip edges with unknown handles
295→    const atEntry =
296→      (connectsAsTarget && targetPos === entryPosition) ||
297→      (connectsAsSource && sourcePos === entryPosition);
298→    const atExit =
299→      (connectsAsSource && sourcePos === exitPosition) ||
300→      (connectsAsTarget && targetPos === exitPosition);
301→
302→    // Bridge only for natural flow directions:
303→    // Entry incoming: External → parent entry → bridge → entryTarget children
304→    // Exit outgoing: exitSource children → bridge → parent exit → External
305→    if (atEntry && connectsAsTarget) {
306→      for (const { nodeId } of entryTargets) {
307→        const childId = `${parentId}_${nodeId}`;
308→        bridgeEdges.push(makeBridgeEdge(
309→          `bridge_${parentId}_${extEdge.id}_entry_${nodeId}`,
310→          parentId, "bridge-entry-source", childId, undefined,
311→        ));
312→      }
313→    }
314→
315→    if (atExit && connectsAsSource) {
316→      for (const { nodeId } of exitSources) {
317→        const childId = `${parentId}_${nodeId}`;
318→        bridgeEdges.push(makeBridgeEdge(
319→          `bridge_${parentId}_${extEdge.id}_exit_${nodeId}`,
320→          childId, `${exitPosition}-source`, parentId, "bridge-exit-target",
321→        ));
322→      }
323→    }
324→  }
325→
326→  return bridgeEdges;
327→}
