 16→export function deserialize(content: string): DeserializeResult {
 17→  const layoutMatch = content.indexOf("--- layout ---");
 18→  if (layoutMatch === -1) {
 19→    throw new Error("Invalid .flowmaid file: missing layout section");
 20→  }
 21→
 22→  const layoutYaml = content.slice(layoutMatch + "--- layout ---".length).trim();
 23→  const layout: FlowmaidLayout = parse(layoutYaml);
 24→
 25→  const nodes: FlowNode[] = [];
 26→  let maxCounter = -1;
 27→
 28→  for (const [id, n] of Object.entries(layout.nodes)) {
 29→    const isComponentInstance = !!n.componentDefinitionId;
 30→    const node: FlowNode = {
 31→      id,
 32→      type: isComponentInstance ? "componentInstance" : n.shape,
 33→      position: n.position,
 34→      data: {
 35→        label: n.label,
 36→        shape: n.shape as FlowNode["data"]["shape"],
 37→      },
 38→      style: n.size ? { width: n.size.width, height: n.size.height } : undefined,
 39→    };
 40→
 41→    // Restore component instance fields
 42→    if (n.componentDefinitionId) node.data.componentDefinitionId = n.componentDefinitionId;
 43→    if (n.componentInstanceName) node.data.componentInstanceName = n.componentInstanceName;
 44→    if (n.componentSyncVersion !== undefined) node.data.componentSyncVersion = n.componentSyncVersion;
 45→    // componentLabelOverrides is deprecated — ignored on import
 46→    if (n.collapsed) node.data.collapsed = n.collapsed;
 47→    if (n.expandedSize) node.data.expandedSize = n.expandedSize;
 48→
 49→    // Restore style properties
 50→    if (n.fillColor) node.data.fillColor = n.fillColor;
 51→    if (n.fillOpacity !== undefined) node.data.fillOpacity = n.fillOpacity;
 52→    if (n.fillLightness !== undefined) node.data.fillLightness = n.fillLightness;
 53→    if (n.borderColor) node.data.borderColor = n.borderColor;
 54→    if (n.borderOpacity !== undefined) node.data.borderOpacity = n.borderOpacity;
 55→    if (n.borderLightness !== undefined) node.data.borderLightness = n.borderLightness;
 56→    if (n.borderWidth) node.data.borderWidth = n.borderWidth;
 57→    if (n.borderStyle) node.data.borderStyle = n.borderStyle;
 58→    if (n.zIndex !== undefined) node.zIndex = n.zIndex;
 59→    if (n.fontSize) node.data.fontSize = n.fontSize;
 60→    if (n.textColor) node.data.textColor = n.textColor;
 61→    if (n.textOpacity !== undefined) node.data.textOpacity = n.textOpacity;
 62→    if (n.textLightness !== undefined) node.data.textLightness = n.textLightness;
 63→    if (n.textAlign) node.data.textAlign = n.textAlign;
 64→    if (n.bold) node.data.bold = n.bold;
 65→    if (n.italic) node.data.italic = n.italic;
 66→    if (n.underline) node.data.underline = n.underline;
 67→
 68→    nodes.push(node);
 69→
 70→    // Track highest counter for auto-id
 71→    if (/^[A-Z]+$/.test(id)) {
 72→      const counter = idToCounter(id);
 73→      if (counter > maxCounter) maxCounter = counter;
 74→    }
 75→  }
 76→
 77→  const edges: FlowEdge[] = [];
 78→  for (const [id, e] of Object.entries(layout.edges)) {
 79→    const edge: FlowEdge = {
 80→      id,
 81→      source: e.source,
 82→      target: e.target,
 83→      type: "labeled",
 84→      sourceHandle: e.sourceHandle,
 85→      targetHandle: e.targetHandle,
 86→      data: {
 87→        label: e.label ?? "",
 88→        edgeType: e.edgeType ?? "bezier",
 89→        markerStart: e.markerStart,
 90→        markerEnd: e.markerEnd ?? "arrowclosed",
 91→        strokeWidth: e.strokeWidth,
 92→        strokeColor: e.strokeColor,
 93→        strokeOpacity: e.strokeOpacity,
 94→        strokeLightness: e.strokeLightness,
 95→        strokeStyle: e.strokeStyle,
 96→        waypoints: e.waypoints,
 97→      },
 98→    };
 99→
100→    edges.push(edge);
101→  }
102→
103→  // Regenerate child nodes and internal edges for component instances
104→  const componentDefinitions = layout.componentDefinitions ?? [];
105→
106→  const allChildNodes: FlowNode[] = [];
107→  const allChildEdges: FlowEdge[] = [];
108→
109→  for (const node of nodes) {
110→    if (!node.data.componentDefinitionId) continue;
111→    const def = componentDefinitions.find((d) => d.id === node.data.componentDefinitionId);
112→    if (!def) continue;
113→
114→    const isCollapsed = node.data.collapsed ?? false;
115→
116→    const { childNodes, childEdges } = generateComponentChildren({
117→      parentId: node.id,
118→      def,
119→      hidden: isCollapsed,
120→    });
121→
122→    allChildNodes.push(...childNodes);
123→    allChildEdges.push(...childEdges);
124→  }
125→
126→  // Generate bridge edges for component instances
127→  const allNodes = [...nodes, ...allChildNodes];
128→  const allEdgesBeforeBridge = [...edges, ...allChildEdges];
129→  const bridgeEdges: FlowEdge[] = [];
130→
131→  for (const node of nodes) {
132→    if (!node.data.componentDefinitionId) continue;
133→    const def = componentDefinitions.find((d) => d.id === node.data.componentDefinitionId);
134→    if (!def) continue;
135→
136→    const bridges = generateBridgeEdges({
137→      parentId: node.id,
138→      def,
139→      allEdges: allEdgesBeforeBridge,
140→      direction: def.direction ?? layout.direction,
141→    });
142→
143→    const isCollapsed = node.data.collapsed ?? false;
144→    for (const b of bridges) {
145→      if (isCollapsed) b.hidden = true;
146→      bridgeEdges.push(b);
147→    }
148→  }
149→
150→  return {
151→    nodes: allNodes,
152→    edges: [...allEdgesBeforeBridge, ...bridgeEdges],
153→    direction: layout.direction ?? "TD",
154→    nextIdCounter: maxCounter + 1,
155→    componentDefinitions,
156→  };
157→}
