  borderWidth?: number;
  borderStyle?: BorderStyle;
  fontSize?: number;
  textColor?: string;
  textOpacity?: number;
  textLightness?: number;
  textAlign?: TextAlign;
  bold?: boolean;
  italic?: boolean;
  underline?: boolean;
}

export interface ComponentInternalEdge {
  id: string;
  source: string;
  target: string;
  label?: string;
  sourceHandle?: string;
  targetHandle?: string;
  edgeType?: EdgeType;
  markerStart?: MarkerStyle;
  markerEnd?: MarkerStyle;
  strokeWidth?: number;
