  4→import type { FlowNode, FlowEdge } from "@/store/types";
  5→import type { ComponentDefinition } from "@/types/flow";
  6→
  7→describe("Component serialize/deserialize", () => {
  8→  const definition: ComponentDefinition = {
  9→    id: "sf1",
 10→    name: "Auth",
 11→    version: 2,
 12→    nodes: [
 13→      { id: "n1", label: "Start", shape: "stadium", position: { x: 50, y: 0 } },
 14→      { id: "n2", label: "End", shape: "stadium", position: { x: 50, y: 80 } },
 15→    ],
 16→    edges: [{ id: "e1", source: "n1", target: "n2" }],
 17→    entryNodeId: "n1",
 18→    exitNodeId: "n2",
 19→  };
 20→
 21→  const instanceNode: FlowNode = {
 22→    id: "A",
 23→    type: "componentInstance",
 24→    position: { x: 100, y: 100 },
 25→    data: {
 26→      label: "Auth Instance",
 27→      shape: "rectangle",
 28→      componentDefinitionId: "sf1",
 29→      componentInstanceName: "Auth Instance",
 30→      componentSyncVersion: 2,
 31→      collapsed: false,
 32→    },
 33→    style: { width: 200, height: 150 },
 34→  };
 35→
 36→  // Child nodes (would be created by placeComponentInstance in real usage)
 37→  const childNodes: FlowNode[] = definition.nodes.map((n) => ({
 38→    id: `A_${n.id}`,
 39→    type: n.shape,
 40→    position: { x: n.position.x + 20, y: n.position.y + 56 },
 41→    parentId: "A",
 42→    data: {
 43→      label: n.id === "n1" ? "Custom Start" : n.label,
 44→      shape: n.shape,
 45→      componentParentId: "A",
 46→      componentInternalId: n.id,
 47→    },
 48→  }));
 49→
 50→  const childEdges: FlowEdge[] = [{
 51→    id: "A_e1",
 52→    source: "A_n1",
 53→    target: "A_n2",
 54→    type: "labeled",
 55→    data: { label: "", edgeType: "bezier", markerEnd: "arrowclosed" },
 56→  }];
 57→
 58→  it("round-trips component definitions and instances", () => {
