100→        {/* New component card (dashed) */}
101→        <button
102→          className="w-full p-4 rounded border-2 border-dashed border-muted-foreground/30 hover:border-primary/50 hover:bg-primary/5 flex flex-col items-center gap-1 transition-colors cursor-pointer"
