  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { NodeShape, EdgeType, ComponentDefinition, ComponentInternalEdge } from "@/types/flow";
  3→import { MarkerType } from "@xyflow/react";
  4→
  5→export const COMPONENT_HEADER_HEIGHT = 36;
  6→export const COMPONENT_PADDING = 20;
  7→const CHILD_NODE_W = 150;
  8→const CHILD_NODE_H = 50;
  9→const CHILD_SCALE = 0.75;
 10→const MIN_CHILD_W = 40;
 11→const MIN_CHILD_H = 20;
 12→
 13→function markerStyleToMarker(style?: string, color?: string) {
 14→  switch (style) {
 15→    case "arrow":
 16→      return color ? { type: MarkerType.Arrow, color } : { type: MarkerType.Arrow };
 17→    case "arrowclosed":
 18→      return color ? { type: MarkerType.ArrowClosed, color } : { type: MarkerType.ArrowClosed };
 19→    case "none":
 20→      return undefined;
 21→    default:
 22→      return undefined;
 23→  }
 24→}
 25→
 26→interface GenerateChildrenOptions {
 27→  parentId: string;
 28→  def: ComponentDefinition;
 29→  hidden?: boolean;
 30→  direction?: "TD" | "LR";
 31→}
 32→
 33→interface GenerateChildrenResult {
 34→  childNodes: FlowNode[];
 35→  childEdges: FlowEdge[];
 36→}
 37→
 38→export function generateComponentChildren(opts: GenerateChildrenOptions): GenerateChildrenResult {
 39→  const { parentId, def, hidden = false, direction } = opts;
 40→  const effectiveDirection = direction ?? def.direction ?? "TD";
 41→
 42→  // Exclude entry/exit nodes
 43→  const excludeIds = new Set<string>();
 44→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
 45→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
 46→
 47→  // Find min position to normalize origin
 48→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
 49→  const minX = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.x)) : 0;
 50→  const minY = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.y)) : 0;
 51→
 52→  const childNodes: FlowNode[] = visibleNodes
 53→    .map((n) => {
 54→      const origW = n.style?.width ?? CHILD_NODE_W;
 55→      const origH = n.style?.height ?? CHILD_NODE_H;
 56→      return {
 57→        id: `${parentId}_${n.id}`,
 58→        type: n.shape,
 59→        position: {
 60→          x: (n.position.x - minX) * CHILD_SCALE + COMPONENT_PADDING,
 61→          y: (n.position.y - minY) * CHILD_SCALE + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING,
 62→        },
 63→        parentId,
 64→        extent: "parent" as const,
 65→        selectable: false,
 66→        draggable: false,
 67→        data: {
 68→          label: n.label,
 69→          shape: n.shape as NodeShape,
 70→          componentParentId: parentId,
 71→          componentInternalId: n.id,
 72→          ...(n.fillColor ? { fillColor: n.fillColor } : {}),
 73→          ...(n.fillOpacity !== undefined ? { fillOpacity: n.fillOpacity } : {}),
 74→          ...(n.fillLightness !== undefined ? { fillLightness: n.fillLightness } : {}),
 75→          ...(n.borderColor ? { borderColor: n.borderColor } : {}),
 76→          ...(n.borderOpacity !== undefined ? { borderOpacity: n.borderOpacity } : {}),
 77→          ...(n.borderLightness !== undefined ? { borderLightness: n.borderLightness } : {}),
 78→          ...(n.borderWidth ? { borderWidth: n.borderWidth } : {}),
 79→          ...(n.borderStyle ? { borderStyle: n.borderStyle } : {}),
 80→          ...(n.fontSize ? { fontSize: n.fontSize } : {}),
 81→          ...(n.textColor ? { textColor: n.textColor } : {}),
 82→          ...(n.textOpacity !== undefined ? { textOpacity: n.textOpacity } : {}),
 83→          ...(n.textLightness !== undefined ? { textLightness: n.textLightness } : {}),
 84→          ...(n.textAlign ? { textAlign: n.textAlign } : {}),
 85→          ...(n.bold ? { bold: n.bold } : {}),
 86→          ...(n.italic ? { italic: n.italic } : {}),
 87→          ...(n.underline ? { underline: n.underline } : {}),
 88→        },
 89→        style: {
 90→          width: Math.round(origW * CHILD_SCALE),
 91→          height: Math.round(origH * CHILD_SCALE),
 92→        },
 93→        hidden,
 94→      };
 95→    });
 96→
 97→  // Exclude edges connected to entry/exit nodes
 98→  // Default handles for child edges: direction-aware
 99→  const defaultSourceHandle = effectiveDirection === "LR" ? "right-source" : "bottom-source";
100→  const defaultTargetHandle = effectiveDirection === "LR" ? "left-target" : "top-target";
101→
102→  const childEdges: FlowEdge[] = def.edges
103→    .filter((e) => !excludeIds.has(e.source) && !excludeIds.has(e.target))
104→    .map((e) => ({
105→      id: `${parentId}_${e.id}`,
106→      source: `${parentId}_${e.source}`,
107→      target: `${parentId}_${e.target}`,
108→      sourceHandle: e.sourceHandle ?? defaultSourceHandle,
109→      targetHandle: e.targetHandle ?? defaultTargetHandle,
110→      type: "labeled",
111→      selectable: false,
112→      markerEnd: markerStyleToMarker(e.markerEnd ?? "arrowclosed", e.strokeColor) ?? { type: MarkerType.ArrowClosed },
113→      markerStart: markerStyleToMarker(e.markerStart, e.strokeColor),
114→      data: {
115→        label: e.label ?? "",
116→        edgeType: (e.edgeType ?? "bezier") as EdgeType,
117→        markerStart: e.markerStart,
118→        markerEnd: e.markerEnd ?? ("arrowclosed" as const),
119→        ...(e.strokeWidth ? { strokeWidth: e.strokeWidth } : {}),
120→        ...(e.strokeColor ? { strokeColor: e.strokeColor } : {}),
121→        ...(e.strokeOpacity !== undefined ? { strokeOpacity: e.strokeOpacity } : {}),
122→        ...(e.strokeLightness !== undefined ? { strokeLightness: e.strokeLightness } : {}),
123→        ...(e.strokeStyle ? { strokeStyle: e.strokeStyle } : {}),
124→      },
125→      hidden,
126→    }));
127→
128→  return { childNodes, childEdges };
129→}
