131→export function calculateComponentSize(def: ComponentDefinition): { width: number; height: number } {
132→  // Exclude entry/exit nodes from size calculation
133→  const excludeIds = new Set<string>();
134→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
135→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
136→
137→  const sizeNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
138→  const sMinX = sizeNodes.length > 0 ? Math.min(...sizeNodes.map((n) => n.position.x)) : 0;
139→  const sMinY = sizeNodes.length > 0 ? Math.min(...sizeNodes.map((n) => n.position.y)) : 0;
140→
141→  let maxX = 0;
142→  let maxY = 0;
143→  for (const n of sizeNodes) {
144→    const right = (n.position.x - sMinX + (n.style?.width ?? CHILD_NODE_W)) * CHILD_SCALE;
145→    const bottom = (n.position.y - sMinY + (n.style?.height ?? CHILD_NODE_H)) * CHILD_SCALE;
146→    if (right > maxX) maxX = right;
147→    if (bottom > maxY) maxY = bottom;
148→  }
149→  return {
150→    width: Math.max(200, Math.round(maxX) + COMPONENT_PADDING * 2),
151→    height: Math.max(120, Math.round(maxY) + COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING * 2),
152→  };
153→}
154→
155→/**
156→ * Recompute child node positions and sizes from the definition's base layout,
157→ * scaled to fit the current parent content area. This avoids compound scaling errors.
158→ */
159→export function rescaleComponentChildren(
160→  childNodes: FlowNode[],
161→  parentId: string,
162→  def: ComponentDefinition,
163→  parentW: number,
164→  parentH: number,
165→): FlowNode[] {
166→  const baseSize = calculateComponentSize(def);
167→  const baseContentW = baseSize.width - COMPONENT_PADDING * 2;
168→  const baseContentH = baseSize.height - COMPONENT_HEADER_HEIGHT - COMPONENT_PADDING * 2;
169→  const currentContentW = parentW - COMPONENT_PADDING * 2;
170→  const currentContentH = parentH - COMPONENT_HEADER_HEIGHT - COMPONENT_PADDING * 2;
171→  if (baseContentW <= 0 || baseContentH <= 0 || currentContentW <= 0 || currentContentH <= 0) return childNodes;
172→
173→  const scale = Math.min(currentContentW / baseContentW, currentContentH / baseContentH);
174→
175→  // Exclude entry/exit nodes from the definition (same logic as generateComponentChildren)
176→  const excludeIds = new Set<string>();
177→  if (def.entryNodeId) excludeIds.add(def.entryNodeId);
178→  if (def.exitNodeId) excludeIds.add(def.exitNodeId);
179→  const visibleNodes = def.nodes.filter((n) => !excludeIds.has(n.id));
180→  const minX = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.x)) : 0;
181→  const minY = visibleNodes.length > 0 ? Math.min(...visibleNodes.map((n) => n.position.y)) : 0;
182→
183→  // Build a map from definition node id → base position/size
184→  const baseMap = new Map<string, { x: number; y: number; w: number; h: number }>();
185→  for (const n of visibleNodes) {
186→    baseMap.set(n.id, {
187→      x: (n.position.x - minX) * CHILD_SCALE,
188→      y: (n.position.y - minY) * CHILD_SCALE,
189→      w: (n.style?.width ?? CHILD_NODE_W) * CHILD_SCALE,
190→      h: (n.style?.height ?? CHILD_NODE_H) * CHILD_SCALE,
191→    });
192→  }
193→
194→  return childNodes.map((child) => {
195→    if (child.data.componentParentId !== parentId) return child;
196→    const internalId = child.data.componentInternalId as string | undefined;
197→    if (!internalId) return child;
198→    const base = baseMap.get(internalId);
199→    if (!base) return child;
200→
201→    return {
202→      ...child,
203→      position: {
204→        x: COMPONENT_PADDING + base.x * scale,
205→        y: COMPONENT_HEADER_HEIGHT + COMPONENT_PADDING + base.y * scale,
206→      },
207→      style: {
208→        ...child.style,
209→        width: Math.max(MIN_CHILD_W, Math.round(base.w * scale)),
210→        height: Math.max(MIN_CHILD_H, Math.round(base.h * scale)),
211→      },
212→    };
213→  });
214→}
